package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class LinkedTreeMap_rotateLeft_Test {

  LinkedTreeMap<String, String> map;

  static class Node<K, V> {
    K key;
    V value;
    Node<K, V> left;
    Node<K, V> right;
    Node<K, V> parent;
    int height;

    Node(K key, V value) {
      this.key = key;
      this.value = value;
      this.height = 1;
    }
  }

  @BeforeEach
  void setUp() {
    map = new LinkedTreeMap<>();
  }

  @Test
  void rotateLeft_shouldRotateProperly() throws Exception {
    // Create nodes to form the tree structure needed for rotateLeft
    Node<String, String> root = new Node<>("root", "r");
    Node<String, String> left = new Node<>("left", "l");
    Node<String, String> pivot = new Node<>("pivot", "p");
    Node<String, String> pivotLeft = new Node<>("pivotLeft", "pl");
    Node<String, String> pivotRight = new Node<>("pivotRight", "pr");

    // Setup relations
    root.left = left;
    root.right = pivot;
    left.parent = root;
    pivot.parent = root;
    pivot.left = pivotLeft;
    pivot.right = pivotRight;
    pivotLeft.parent = pivot;
    pivotRight.parent = pivot;

    // Set heights to test height recalculation
    left.height = 2;
    pivotLeft.height = 3;
    pivotRight.height = 4;
    root.height = 5;
    pivot.height = 6;

    // Spy on map to verify replaceInParent call
    LinkedTreeMap<String, String> spyMap = spy(map);

    // Use reflection to get private rotateLeft method
    Method rotateLeftMethod = LinkedTreeMap.class.getDeclaredMethod("rotateLeft", Node.class);
    rotateLeftMethod.setAccessible(true);

    // Use reflection to get private replaceInParent method
    Method replaceInParentMethod = LinkedTreeMap.class.getDeclaredMethod("replaceInParent", Node.class, Node.class);
    replaceInParentMethod.setAccessible(true);

    // Stub replaceInParent to call real method to avoid NullPointerException
    doCallRealMethod().when(spyMap).replaceInParent(any(), any());

    // Call rotateLeft on spyMap with root node
    rotateLeftMethod.invoke(spyMap, root);

    // Verify structure after rotation:
    // pivot should replace root as parent's child
    // root should be left child of pivot
    // root.right should be pivotLeft
    // pivotLeft.parent should be root
    assertSame(pivot.left, root);
    assertSame(root.parent, pivot);
    assertSame(root.right, pivotLeft);
    assertSame(pivotLeft.parent, root);

    // Heights should be updated correctly
    int expectedRootHeight = Math.max(left.height, pivotLeft.height) + 1;
    int expectedPivotHeight = Math.max(expectedRootHeight, pivotRight.height) + 1;
    assertEquals(expectedRootHeight, root.height);
    assertEquals(expectedPivotHeight, pivot.height);

    // Verify replaceInParent was called with correct arguments
    verify(spyMap).replaceInParent(root, pivot);
  }

  @Test
  void rotateLeft_withNullPivotLeft_shouldHandleNull() throws Exception {
    Node<String, String> root = new Node<>("root", "r");
    Node<String, String> left = new Node<>("left", "l");
    Node<String, String> pivot = new Node<>("pivot", "p");
    Node<String, String> pivotRight = new Node<>("pivotRight", "pr");

    root.left = left;
    root.right = pivot;
    left.parent = root;
    pivot.parent = root;
    pivot.left = null;
    pivot.right = pivotRight;
    pivotRight.parent = pivot;

    left.height = 3;
    pivotRight.height = 4;
    root.height = 5;
    pivot.height = 6;

    LinkedTreeMap<String, String> spyMap = spy(map);
    Method rotateLeftMethod = LinkedTreeMap.class.getDeclaredMethod("rotateLeft", Node.class);
    rotateLeftMethod.setAccessible(true);
    doCallRealMethod().when(spyMap).replaceInParent(any(), any());

    rotateLeftMethod.invoke(spyMap, root);

    // pivot.left should be root
    assertSame(pivot.left, root);
    // root.parent should be pivot
    assertSame(root.parent, pivot);
    // root.right should be null since pivot.left is null
    assertNull(root.right);

    int expectedRootHeight = Math.max(left.height, 0) + 1;
    int expectedPivotHeight = Math.max(expectedRootHeight, pivotRight.height) + 1;
    assertEquals(expectedRootHeight, root.height);
    assertEquals(expectedPivotHeight, pivot.height);

    verify(spyMap).replaceInParent(root, pivot);
  }

  @Test
  void rotateLeft_withNullLeft_shouldHandleNull() throws Exception {
    Node<String, String> root = new Node<>("root", "r");
    Node<String, String> pivot = new Node<>("pivot", "p");
    Node<String, String> pivotLeft = new Node<>("pivotLeft", "pl");
    Node<String, String> pivotRight = new Node<>("pivotRight", "pr");

    root.left = null;
    root.right = pivot;
    pivot.parent = root;
    pivot.left = pivotLeft;
    pivot.right = pivotRight;
    pivotLeft.parent = pivot;
    pivotRight.parent = pivot;

    pivotLeft.height = 2;
    pivotRight.height = 3;
    root.height = 4;
    pivot.height = 5;

    LinkedTreeMap<String, String> spyMap = spy(map);
    Method rotateLeftMethod = LinkedTreeMap.class.getDeclaredMethod("rotateLeft", Node.class);
    rotateLeftMethod.setAccessible(true);
    doCallRealMethod().when(spyMap).replaceInParent(any(), any());

    rotateLeftMethod.invoke(spyMap, root);

    assertSame(pivot.left, root);
    assertSame(root.parent, pivot);
    assertSame(root.right, pivotLeft);
    assertSame(pivotLeft.parent, root);

    int expectedRootHeight = Math.max(0, pivotLeft.height) + 1;
    int expectedPivotHeight = Math.max(expectedRootHeight, pivotRight.height) + 1;
    assertEquals(expectedRootHeight, root.height);
    assertEquals(expectedPivotHeight, pivot.height);

    verify(spyMap).replaceInParent(root, pivot);
  }
}
